from dataclasses import dataclass, field
from typing import Optional, List
from datetime import datetime

@dataclass
class Priority:
    level: int  # 1-5
    label: str
    color: str

    def __post_init__(self):
        if not 1 <= self.level <= 5:
            raise ValueError(f"Priority level must be 1-5, got {self.level}")

# Standard priority levels
PRIORITIES = {
    1: Priority(1, "critical", "red"),
    2: Priority(2, "high", "orange"),
    3: Priority(3, "medium", "yellow"),
    4: Priority(4, "low", "green"),
    5: Priority(5, "minimal", "gray"),
}

@dataclass
class Task:
    title: str
    priority: Priority
    tags: List[str] = field(default_factory=list)
    created_at: datetime = field(default_factory=datetime.now)
    completed_at: Optional[datetime] = None
    blocked_by: List[str] = field(default_factory=list)  # task titles

    @property
    def is_blocked(self) -> bool:
        return len(self.blocked_by) > 0

    @property
    def is_completed(self) -> bool:
        return self.completed_at is not None


